#include<bits/stdc++.h>
using namespace std;
constexpr int N=4e6+3,nulltag=2014514191,mod=1e9+7;;
struct FHQ_Treap
{
    struct node
    {
        int l,r;
        int val;
        int siz,sum;
        bool rev_tag;
        int add_tag,upd_tag;
    }t[N];
    int b[300010];
    int tot,cnt,root;
    int newnode(int v)
    {
        t[++tot].val=v;
        t[tot].l=t[tot].r=0;
        t[tot].siz=1;
        t[tot].sum=v;
        t[tot].rev_tag=0;
        t[tot].add_tag=0;
        t[tot].upd_tag=nulltag;
        return tot;
    }
    int copynode(int v)
    {
        t[++tot]=t[v];
        return tot;
    }
    int dfs11(int x)
    {
        if(x==0)
        {
            return 0;
        }
        t[++tot]=t[x];
        int now=tot;
        t[now].l=dfs11(t[x].l);
        t[now].r=dfs11(t[x].r);
        return now;
    }
    int copytree(int v)
    {
        return dfs11(v);
    }
    void pushup(int x)
    {
        t[x].siz=t[t[x].l].siz+t[t[x].r].siz+1;
        t[x].sum=((t[t[x].l].sum+t[t[x].r].sum)%mod+t[x].val)%mod;
    }
    void pushrev(int x)
    {
        if(x)
        {
            ::swap(t[x].l,t[x].r);
            t[x].rev_tag^=1;
        }
    }
    void pushupd(int x,int v)
    {
        if(x&&v!=nulltag)
        {
            t[x].val=v;
            t[x].sum=1ll*t[x].siz*v%mod;
            t[x].add_tag=0;
            t[x].upd_tag=v;
        }
    }
    void pushadd(int x,int v)
    {
        if(x&&v)
        {
            t[x].val=(t[x].val+v)%mod;
            t[x].sum=(t[x].sum+1ll*t[x].siz*v%mod)%mod;
            t[x].add_tag=(t[x].add_tag+v)%mod;
        }
    }
    void pushdown(int x)
    {
        if(!x)
        {
            return;
        }
        if(t[x].rev_tag||t[x].upd_tag!=nulltag||t[x].add_tag)
        {
            if(t[x].l)
            {
                t[x].l=copynode(t[x].l);
            }
            if(t[x].r)
            {
                t[x].r=copynode(t[x].r);
            }
        }
        if(t[x].rev_tag)
        {
            pushrev(t[x].l);
            pushrev(t[x].r);
            t[x].rev_tag=0;
        }
        if(t[x].upd_tag!=nulltag)
        {
            pushupd(t[x].l,t[x].upd_tag);
            pushupd(t[x].r,t[x].upd_tag);
            t[x].upd_tag=nulltag;
        }
        if(t[x].add_tag)
        {
            pushadd(t[x].l,t[x].add_tag);
            pushadd(t[x].r,t[x].add_tag);
            t[x].add_tag=0;
        }
    }
    void split(int p,int v,int &x,int &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        pushdown(p);
        if(t[t[p].l].siz+1<=v)
        {
            x=copynode(p);
            split(t[x].r,v-t[t[p].l].siz-1,t[x].r,y);
            pushup(x);
        }
        else
        {
            y=copynode(p);
            split(t[y].l,v,x,t[y].l);
            pushup(y);
        }
    }
    int merge(int x,int y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        if(rand()%(t[x].siz+t[y].siz)<t[x].siz)
        {
            pushdown(x);
            x=copynode(x);
            t[x].r=merge(t[x].r,y);
            pushup(x);
            return x;
        }
        else
        {
            pushdown(y);
            y=copynode(y);
            t[y].l=merge(x,t[y].l);
            pushup(y);
            return y;
        }
    }
    void push_back(int v)
    {
        root=merge(root,newnode(v));
    }
    void reverse(int l,int r)
    {
        int x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        pushrev(y);
        root=merge(merge(x,y),z);
    }
    void update(int l,int r,int v)
    {
        int x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        pushupd(y,v);
        root=merge(merge(x,y),z);
    }
    void add(int l,int r,int v)
    {
        int x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        pushadd(y,v);
        root=merge(merge(x,y),z);
    }
    int getsum(int l,int r)
    {
        int x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        int ans=t[y].sum;
        root=merge(merge(x,y),z);
        return ans;
    }
    void swap(int l1,int r1,int l2,int r2)
    {
        if(l1>l2)
        {
            ::swap(l1,l2);
            ::swap(r1,r2);
        }
        int a,b,c,d,e;
        split(root,r2,d,e);
        split(d,l2-1,c,d);
        split(c,r1,b,c);
        split(b,l1-1,a,b);
        ::swap(b,d);
        root=merge(merge(merge(merge(a,b),c),d),e);
    }
    void copy(int l1,int r1,int l2,int r2)
    {
        if(l1<l2)
        {
            int a,b,c,d,e;
            split(root,r2,d,e);
            split(d,l2-1,c,d);
            split(c,r1,b,c);
            split(b,l1-1,a,b);
            d=copynode(b);
            root=merge(merge(merge(merge(a,b),c),d),e);
        }
        else
        {
            int a,b,c,d,e;
            split(root,r1,d,e);
            split(d,l1-1,c,d);
            split(c,r2,b,c);
            split(b,l2-1,a,b);
            b=copynode(d);
            root=merge(merge(merge(merge(a,b),c),d),e);
        }
    }
    void __get_val(int x)
    {
        if(x==0)
        {
            return;
        }
        pushdown(x);
        __get_val(t[x].l);
        b[++cnt]=t[x].val;
        __get_val(t[x].r);
    }
    int __rebuild(int l,int r)
    {
        if(l>r)
        {
            return 0;
        }
        int mid=(l+r)>>1;
        int tmp=__rebuild(l,mid-1);
        int x=newnode(b[mid]);
        t[x].l=tmp;
        t[x].r=__rebuild(mid+1,r);
        pushup(x);
        return x;
    }
    void rebuild()
    {
        cnt=0;
        __get_val(root);
        tot=root=0;
        root=__rebuild(1,cnt);
    }
    int size()
    {
        return t[root].siz;
    }
}t;
int main()
{
    srand(time(0));
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        t.push_back(x);
    }
    while(m--)
    {
        int op,l,r,val,l2,r2;
        scanf("%d%d%d",&op,&l,&r);
        if(op==1)
        {
            printf("%d\n",t.getsum(l,r)%mod);
        }
        else if(op==2)
        {
            scanf("%d",&val);
            t.update(l,r,val);
        }
        else if(op==3)
        {
            scanf("%d",&val);
            t.add(l,r,val);
        }
        else if(op==4)
        {
            scanf("%d%d",&l2,&r2);
            t.copy(l,r,l2,r2);
        }
        else if(op==5)
        {
            scanf("%d%d",&l2,&r2);
            t.swap(l,r,l2,r2);
        }
        else
        {
            t.reverse(l,r);
        }
        if(t.tot>3600000)
        {
            t.rebuild();
        }
    }
    t.rebuild();
    for(int i=1;i<=n;i++)
    {
        printf("%d ",t.b[i]%mod);
    }
    return 0;
}
